import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limiting input length to prevent buffer overflow
        int maxLength = Math.min(name.length(), 10);

        // Using StringBuilder to store user input safely
        StringBuilder buffer = new StringBuilder(maxLength);
        buffer.append(name.substring(0, maxLength));

        System.out.println("Welcome, " + buffer.toString());
    }
}
